import React, { useEffect, useState, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  PiggyBank, AlertCircle, ArrowUpCircle, Target, 
  CreditCard, Calendar, TrendingUp, ChevronRight 
} from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [dados, setDados] = useState({
    metaReceita: 0,
    receitaReal: 0,
    metaGasto: 0,
    gastoReal: 0,
    gastoCartao: 0,
    gastoVariavel: 0,
    categoriasDespesa: [],
    objetivosPessoais: [],
    resumo503020: {
      essenciais: { valor: 0, limite: 0 },
      estiloVida: { valor: 0, limite: 0 },
      prioridades: { valor: 0, limite: 0 }
    }
  });

  useEffect(() => {
    buscarDadosCompletos();
  }, []);

  const formatMoney = (v) => {
    const valor = Number(v) || 0;
    return valor.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  async function buscarDadosCompletos() {
    setLoading(true);
    try {
      const agora = new Date();
      const ano = agora.getFullYear();
      const mes = agora.getMonth() + 1;
      const primeiroDia = `${ano}-${String(mes).padStart(2, '0')}-01`;
      const ultimoDia = new Date(ano, mes, 0).toISOString().split('T')[0];

      const [
        { data: metasData },
        { data: proventos },
        { data: comprasVariaveis },
        { data: parcelasMes },
        { data: cats }
      ] = await Promise.all([
        supabase.from('metas').select('*').eq('mes_referencia', mes).eq('ano_referencia', ano),
        supabase.from('proventos').select('valor').gte('data_recebimento', primeiroDia).lte('data_recebimento', ultimoDia),
        supabase.from('compras').select('valor_total, categoria_id').gte('data_compra', primeiroDia).lte('data_compra', ultimoDia),
        supabase.from('parcelas').select('valor_parcela, compras!inner(categoria_id)').gte('data_vencimento', primeiroDia).lte('data_vencimento', ultimoDia),
        supabase.from('categorias').select('*').order('nome', { ascending: true })
      ]);

      const gastosPorCat = {};
      comprasVariaveis?.forEach(c => {
        gastosPorCat[c.categoria_id] = (gastosPorCat[c.categoria_id] || 0) + Number(c.valor_total);
      });
      parcelasMes?.forEach(p => {
        const catId = p.compras?.categoria_id;
        if (catId) {
          gastosPorCat[catId] = (gastosPorCat[catId] || 0) + Number(p.valor_parcela);
        }
      });

      const todasCategoriasConsolidadas = (cats || []).map(cat => {
        const metaEncontrada = metasData?.find(m => m.categoria_id === cat.id);
        return {
          ...cat,
          gastoReal: Number(gastosPorCat[cat.id] || 0),
          metaValor: metaEncontrada ? Number(metaEncontrada.valor_meta) : 0,
          tipoMeta: metaEncontrada?.tipo_meta || 'despesa',
          nomeMetaPessoal: metaEncontrada?.nome_meta_pessoal || null
        };
      });

      const categoriasDespesa = todasCategoriasConsolidadas.filter(c => c.tipo === 'despesa' && c.tipoMeta !== 'pessoal');
      const objetivosPessoais = todasCategoriasConsolidadas.filter(c => c.tipoMeta === 'pessoal');

      const totalReceitaReal = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;
      const totalVariavel = comprasVariaveis?.reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;
      const totalCartao = parcelasMes?.reduce((acc, cur) => acc + Number(cur.valor_parcela), 0) || 0;
      const totalGastoReal = totalVariavel + totalCartao;

      const totalMetaGasto = metasData?.filter(m => m.tipo_meta === 'despesa').reduce((a, b) => a + Number(b.valor_meta), 0) || 0;
      const totalMetaReceita = metasData?.filter(m => m.tipo_meta === 'provento').reduce((a, b) => a + Number(b.valor_meta), 0) || 0;

      // Lógica 50-30-20 baseada na Receita Real
      const resumo503020 = {
        essenciais: { valor: 0, limite: totalReceitaReal * 0.5 },
        estiloVida: { valor: 0, limite: totalReceitaReal * 0.3 },
        prioridades: { valor: 0, limite: totalReceitaReal * 0.2 }
      };

      const categoriasEssenciais = ['Aluguel', 'Saúde', 'Educação', 'Mercado', 'Transporte', 'Água', 'Luz', 'Moradia'];

      todasCategoriasConsolidadas.forEach(cat => {
        if (cat.tipoMeta === 'pessoal') {
          resumo503020.prioridades.valor += cat.gastoReal;
        } else if (categoriasEssenciais.some(e => cat.nome.includes(e))) {
          resumo503020.essenciais.valor += cat.gastoReal;
        } else if (cat.tipo === 'despesa') {
          resumo503020.estiloVida.valor += cat.gastoReal;
        }
      });

      setDados({
        metaReceita: totalMetaReceita,
        receitaReal: totalReceitaReal,
        metaGasto: totalMetaGasto,
        gastoReal: totalGastoReal,
        gastoCartao: totalCartao,
        gastoVariavel: totalVariavel,
        categoriasDespesa,
        objetivosPessoais,
        resumo503020
      });

    } catch (err) {
      console.error("Erro ao carregar orçamento:", err);
    } finally {
      setLoading(false);
    }
  }

  const porcGasto = useMemo(() => dados.metaGasto > 0 ? (dados.gastoReal / dados.metaGasto) * 100 : 0, [dados.gastoReal, dados.metaGasto]);
  const mesAtualNome = new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date());

  if (loading) return <div className="loading-state">Calculando seu equilíbrio financeiro...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <div className="header-info">
          <h2>Gestão Estratégica</h2>
          <div className="badge-mes">
            <Calendar size={14} />
            <span>{mesAtualNome.toUpperCase()}</span>
          </div>
        </div>
        <button className="btn-ajuste-premium" onClick={() => window.location.href='/metas'}>
          <Target size={18} /> <span>Definir Metas</span>
        </button>
      </header>

      {/* CARD GLOBAL COM ALERTA DE DÉFICIT */}
      <section className="main-stats-card">
        <div className="stats-header">
          <div className="stats-main-info">
            <span className="stats-label">Teto de Gastos Definido</span>
            <div className="stats-values">
              <h3>{formatMoney(dados.gastoReal)}</h3>
              <span className="separator">/</span>
              <span className="goal-value">{formatMoney(dados.metaGasto)}</span>
            </div>
          </div>
          <div className={`status-icon ${dados.gastoReal > dados.metaGasto ? 'danger' : 'success'}`}>
             <PiggyBank size={32} />
          </div>
        </div>
        
        <div className="premium-progress-wrapper">
          <div className="premium-progress-bg">
            <div 
              className={`premium-progress-fill ${porcGasto > 100 ? 'critical' : ''}`}
              style={{ width: `${Math.min(porcGasto, 100)}%` }}
            />
          </div>
          <div className="progress-details">
            <span className="perc-text">{porcGasto.toFixed(1)}% do teto</span>
            {dados.receitaReal < dados.metaGasto && (
              <span className="deficit-badge"><AlertCircle size={12}/> Orçamento Deficitário</span>
            )}
          </div>
        </div>
      </section>

      {/* ANÁLISE 50-30-20 VISUAL */}
      <section className="alocacao-503020">
        <h3 className="premium-section-title">Equilíbrio 50-30-20 (Real)</h3>
        <div className="alocacao-grid">
          {[
            { label: 'Essenciais (50%)', key: 'essenciais', color: '#3b82f6' },
            { label: 'Estilo de Vida (30%)', key: 'estiloVida', color: '#f59e0b' },
            { label: 'Prioridades (20%)', key: 'prioridades', color: '#8b5cf6' }
          ].map(item => (
            <div key={item.key} className="alocacao-card">
              <div className="alocacao-info">
                <span className="aloc-label">{item.label}</span>
                <span className="aloc-valor">{formatMoney(dados.resumo503020[item.key].valor)}</span>
              </div>
              <div className="aloc-progress-bg">
                <div 
                  className={`aloc-progress-fill ${dados.resumo503020[item.key].valor > dados.resumo503020[item.key].limite && item.key !== 'prioridades' ? 'danger' : ''}`}
                  style={{ 
                    width: `${Math.min((dados.resumo503020[item.key].valor / (dados.receitaReal || 1)) * 100, 100)}%`,
                    backgroundColor: item.color 
                  }}
                />
              </div>
              <small>Limite sugerido: {formatMoney(dados.resumo503020[item.key].limite)}</small>
            </div>
          ))}
        </div>
      </section>

      <div className="summary-grid-premium">
        <div className="summary-card-premium inbound">
          <div className="card-top">
            <div className="icon-box"><ArrowUpCircle size={20} /></div>
            <span className="card-tag">Receita Real</span>
          </div>
          <p className="card-value">{formatMoney(dados.receitaReal)}</p>
          <span className="card-sub">Meta esperada: {formatMoney(dados.metaReceita)}</span>
        </div>

        <div className="summary-card-premium outbound">
          <div className="card-top">
            <div className="icon-box"><CreditCard size={20} /></div>
            <span className="card-tag">Meios de Pagamento</span>
          </div>
          <div className="split-values">
            <div className="split-item">
              <label>Cartão</label>
              <strong>{formatMoney(dados.gastoCartao)}</strong>
            </div>
            <div className="split-item">
              <label>À Vista/Pix</label>
              <strong>{formatMoney(dados.gastoVariavel)}</strong>
            </div>
          </div>
        </div>
      </div>

      {/* OBJETIVOS PESSOAIS */}
      {dados.objetivosPessoais.length > 0 && (
        <section className="objectives-section">
          <h3 className="premium-section-title"><TrendingUp size={18} /> Objetivos Financeiros</h3>
          <div className="objectives-grid">
            {dados.objetivosPessoais.map(meta => {
              const porcPessoal = meta.metaValor > 0 ? (meta.gastoReal / meta.metaValor) * 100 : 0;
              return (
                <div key={meta.id} className="objective-card-premium">
                  <div className="obj-header">
                    <span className="obj-name">{meta.nomeMetaPessoal || meta.nome}</span>
                    <span className="obj-percent">{porcPessoal.toFixed(0)}%</span>
                  </div>
                  <div className="obj-progress-container">
                    <div className="obj-progress-fill" style={{ width: `${Math.min(porcPessoal, 100)}%` }} />
                  </div>
                  <div className="obj-footer">
                    <span className="obj-real">{formatMoney(meta.gastoReal)}</span>
                    <span className="obj-goal">alvo: {formatMoney(meta.metaValor)}</span>
                  </div>
                </div>
              );
            })}
          </div>
        </section>
      )}

      {/* CATEGORIAS */}
      <h3 className="premium-section-title" style={{marginTop: '40px'}}><Target size={18} /> Detalhe por Categoria</h3>
      <div className="categories-grid-premium">
        {dados.categoriasDespesa.map((cat) => {
          const porc = cat.metaValor > 0 ? (cat.gastoReal / cat.metaValor) * 100 : 0;
          const excedeu = cat.gastoReal > cat.metaValor && cat.metaValor > 0;
          return (
            <div key={cat.id} className={`cat-card-premium ${excedeu ? 'exceeded' : ''}`}>
              <div className="cat-card-header">
                <div className="cat-label-group">
                  <div className="cat-indicator" style={{backgroundColor: cat.cor}}></div>
                  <span className="cat-name">{cat.nome}</span>
                </div>
                {excedeu && <AlertCircle size={16} color="#ef4444" />}
              </div>
              <div className="cat-card-body">
                <div className="cat-money-row">
                  <div className="money-col"><label>Real</label><span className="money-val">{formatMoney(cat.gastoReal)}</span></div>
                  <div className="money-col right"><label>Meta</label><span className="money-meta">{formatMoney(cat.metaValor)}</span></div>
                </div>
                <div className="cat-progress-bar">
                  <div className="cat-progress-fill" style={{ width: `${Math.min(porc, 100)}%`, backgroundColor: excedeu ? '#ef4444' : cat.cor }} />
                </div>
                <div className="cat-card-footer"><span>{porc.toFixed(0)}% utilizado</span></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Orcamento;
